#include<bits/stdc++.h>
using namespace std;
set<int> s;
int n,cmd,x;
int main(void){
	cin>>n;
	while(n--){
		cin>>cmd>>x;
		if(cmd==1)
			if(s.find(x)!=s.end())cout<<"Already Exist\n";
			else s.insert(x);
		else if(s.empty())cout<<"Empty\n";
		else{
			set<int>::iterator i=s.lower_bound(x),j=i;
			if(j!=s.begin())j--;
			if(i!=s.end() and x-(*j)>(*i)-x)j=i;
			cout<<(*j)<<'\n';s.erase(j);
		}
	}
	return false;
}
